+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+const plainObject = (value: unknown): value is Record<string, unknown> =>
+  !!value && typeof value === "object" && !Array.isArray(value);
+
+export function flattenConfig(value: Record<string, unknown>): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    if (plainObject(item)) {
+      for (const [childKey, childValue] of Object.entries(flattenConfig(item))) {
+        result[`${key}.${childKey}`] = childValue;
+      }
+    } else {
+      result[key.replace(/-([a-z])/g, (_, char) => char.toUpperCase())] = item;
+    }
+  }
+  return result;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new Error(`Invalid RC entry "${line}".`);
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) throw new Error(`Unterminated RC value for "${key}".`);
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      result[key.replace(/-([a-z])/g, (_, char) => char.toUpperCase())] = value === "true";
+      continue;
+    } else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      result[key.replace(/-([a-z])/g, (_, char) => char.toUpperCase())] = Number(value);
+      continue;
+    }
+    result[key.replace(/-([a-z])/g, (_, char) => char.toUpperCase())] = value;
+  }
+  return result;
+}
+
+async function readFile(path: string): Promise<string | undefined> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as { Deno?: { readTextFile(path: string): Promise<string> } };
+  try {
+    if (Deno) return await Deno.readTextFile(path);
+    const fs = await import("node:fs/promises");
+    return await fs.readFile(path, "utf8");
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT" || (error as { name?: string }).name === "NotFound") return;
+    throw error;
+  }
+}
+
+function cwd(): string {
+  // dnt-shim-ignore
+  const runtime = globalThis as { Deno?: { cwd(): string }; process?: { cwd(): string } };
+  return runtime.Deno?.cwd() ?? runtime.process?.cwd() ?? ".";
+}
+
+function join(path: string, name: string): string {
+  return `${path.replace(/[\\\\/]$/, "")}/${name}`;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<{ values: Record<string, unknown>; path?: string }> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const matches: Array<{ path: string; values: Record<string, unknown> }> = [];
+  for (const directory of paths) {
+    for (const format of formats) {
+      const path = join(directory, `${options.name}${format}`);
+      const content = await readFile(path);
+      if (typeof content === "undefined") continue;
+      try {
+        const parsed = options.parser ? options.parser(content) : format === ".json" ? JSON.parse(content) : parseRc(content);
+        if (!plainObject(parsed)) throw new Error("Config must contain a plain object.");
+        matches.push({ path, values: flattenConfig(parsed) });
+      } catch (error) {
+        throw new ConfigParseError(path, error);
+      }
+      break;
+    }
+    if (matches.length && !options.mergeConfigs) break;
+  }
+  // Earlier paths take precedence.
+  return { path: matches[0]?.path, values: Object.assign({}, ...matches.slice().reverse().map((match) => match.values)) };
+}
