+test("command - config - loads JSON defaults and flattens nested values", async () => {
+  const path = await fixture({
+    "app.json": JSON.stringify({ "user-name": "Ada", server: { port: 8080 }, tags: ["one", "two"] }),
+  });
+  const cmd = new Command().throwErrors()
+    .option("--user-name <name>", "...")
+    .option("--server.port <port:number>", "...")
+    .option("--tags <tag>", "...", { collect: true })
+    .config({ name: "app", searchPaths: [path] });
+  const result = await cmd.parse([]);
+  assertEquals(result.options, { userName: "Ada", "server.port": 8080, tags: ["one", "two"] });
+  assertEquals(cmd.getConfigPath(), `${path}/app.json`);
+  assertEquals(cmd.getConfigValues(), { userName: "Ada", "server.port": 8080, tags: ["one", "two"] });
+});
+
+test("command - config - RC files are parsed and config has lowest precedence", async () => {
+  const path = await fixture({ ".apprc": "# comment\
enabled=false\
port=0\
title=\\"hello world\\"\
" });
+  setEnv("PORT", "3");
+  try {
+    const cmd = new Command().throwErrors()
+      .option("--enabled", "...")
+      .option("--port <port:number>", "...")
+      .option("--title <title>", "...")
+      .env("PORT=<port:number>", "...")
+      .config({ name: "app", searchPaths: [path] });
+    const result = await cmd.parse(["--port", "4"]);
+    assertEquals(result.options, { enabled: false, port: 4, title: "hello world" });
+  } finally {
+    deleteEnv("PORT");
+  }
+});
+
+test("command - config - merges paths with earlier paths taking precedence", async () => {
+  const first = await fixture({ "app.json": '{"port": 1, "name": "first"}' });
+  const second = await fixture({ "app.json": '{"port": 2, "verbose": true}' });
+  const cmd = new Command().throwErrors()
+    .option("--port <port:number>", "...")
+    .option("--name <name>", "...")
+    .option("--verbose", "...")
+    .config({ name: "app", searchPaths: [first, second], mergeConfigs: true });
+  assertEquals((await cmd.parse([])).options, { port: 1, name: "first", verbose: true });
+});
+
